sql:
SELECT COUNT(*) AS total_approved_questions
FROM question_approval
WHERE approval_status = 'approved';

external_knowledge:
- 'after 2005' refers to the time period after January 1, 2005; 
- 'approved' questions are those that have been reviewed and accepted; 
- 'peak ratings' refer to the highest ratings an episode received; 
- 'average viewership' refers to the mean number of viewers for an episode.

sql:
SELECT approval_date, approval_status 
FROM question_approval 
WHERE question_id = 0;

SELECT producer_name
FROM producers
WHERE producer_id = 1;

SELECT writer_name
FROM question_writers
WHERE writer_id = (SELECT MAX(writer_id) FROM question_writers);

SELECT SUM(viewership) AS total_viewership
FROM shows
WHERE show_id = 0;
